mapper.select:
select sum(amount) from orders


        and status = #{status}


        and order_time >= #{dateBegin}


        and order_time < #{dateEnd}

select count(id) from user


        and create_time > #{dateBegin}


        and create_time < #{dateEnd}

select count(id) from orders


        and order_time > #{dateBegin}


        and order_time < #{dateEnd}


        and status = #{status}

select od.name name, sum(od.number) number
from order_detail od left join orders o
on o.id = order_id

    and o.status=#{status}
    and o.order_time > #{beginTime}
    and o.order_time < #{endTime}

group by name
order by number desc limit 10;
